<style>
    .ai-float-box {
        position: fixed;
        top: 180px;
        right: 20px;
        width: 340px;
        background: #fff;
        border: 1px solid rgba(0, 0, 0, 0.05);
        border-radius: 20px;
        box-shadow: 0 15px 40px rgba(0, 0, 0, 0.12);
        z-index: 1000;
        padding: 24px;
        font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
        display: none;
        animation: aiSlideIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    }

    @keyframes  aiSlideIn {
        from {
            transform: translateX(120%);
            opacity: 0;
        }

        to {
            transform: translateX(0);
            opacity: 1;
        }
    }

    .ai-float-box.is-closing {
        animation: aiSlideOut 0.28s cubic-bezier(0.4, 0, 1, 1) forwards;
        pointer-events: none;
    }

    @keyframes  aiSlideOut {
        from {
            transform: translateX(0);
            opacity: 1;
        }

        to {
            transform: translateX(120%);
            opacity: 0;
        }
    }

    .ai-float-box .close-btn {
        position: absolute;
        top: 14px;
        right: 14px;
        display: flex;
        align-items: center;
        justify-content: center;
        width: 26px;
        height: 26px;
        padding: 0;
        border: 0;
        border-radius: 50%;
        background: transparent;
        cursor: pointer;
        color: #999;
        transition: background-color 0.2s ease, color 0.2s ease;
    }

    .ai-float-box .close-btn:hover {
        background-color: #f3f4f6;
        color: #3a424d;
    }

    .ai-float-header {
        display: flex;
        align-items: center;
        gap: 10px;
        margin-bottom: 12px;
    }

    .ai-status-dot {
        width: 10px;
        height: 10px;
        background: #22c55e;
        border-radius: 50%;
    }

    .ai-float-title {
        font-size: 20px;
        font-weight: 700;
        letter-spacing: 0;
    }

    .shimmer-text {
        background: linear-gradient(90deg, #1a1a1a 0%, #20a53a 25%, #1a1a1a 50%, #20a53a 75%, #1a1a1a 100%);
        background-size: 200% auto;
        -webkit-background-clip: text;
        background-clip: text;
        -webkit-text-fill-color: transparent;
        animation: shimmer 6s linear infinite;
    }

    @keyframes  shimmer {
        100% {
            background-position: 200% center;
        }
    }

    .ai-float-desc {
        font-size: 14px;
        color: #666;
        line-height: 1.6;
        margin-bottom: 16px;
    }

