    }

    .ai-feature-icon {
        width: 30px;
        height: 30px;
        background: #f0fdf4;
        color: #20a53a;
        border-radius: 12px;
        display: flex;
        align-items: center;
        justify-content: center;
        flex-shrink: 0;
    }

    .ai-feature-icon svg {
        width: 16px;
        height: 16px;
        fill: none;
        stroke: currentColor;
    }

    .ai-feature-icon svg * {
        fill: none;
