		<script data-cfasync="false" src="/cdn-cgi/scripts/5c5dd728/cloudflare-static/email-decode.min.js"></script><script src="/static/js/jquery-3.3.1.min.js" type="text/javascript" charset="utf-8"></script>
	<script src="/static/layer/layer.js" type="text/javascript" charset="utf-8"></script>
	<script>
		var storage = function (key, value) {
			if (typeof value === 'undefined') {
				return localStorage.getItem(key);
			}
			return localStorage.setItem(key, value);
		};

		var format = function (template, data) {
			return template.replace(/\{\{\s*(.*?)\s*?\}\}/g, function ($0, $1) {
				return data[$1] || '';
			});
		};

		var getUrlParamValue = function (name) {
			if (name == null || name == 'undefined') {
				return null;
			}

			var searchStr = decodeURI(location.search);

			var infoIndex = searchStr.indexOf(name + "=");

			if (infoIndex == -1) {
				return null;
			}

			var searchInfo = searchStr.substring(infoIndex + name.length + 1);

			var tagIndex = searchInfo.indexOf("&");

			if (tagIndex != -1) {
				searchInfo = searchInfo.substring(0, tagIndex);
			}

			return searchInfo;
		}

		// Attempt get token and set user name from url
		if (getUrlParamValue('nonce') && getUrlParamValue('token_type') && getUrlParamValue('token') && getUrlParamValue('username') && getUrlParamValue('ttl')) {
			storage('access-token', getUrlParamValue('token'));
			storage('userName', getUrlParamValue('username'));
			storage('token_type', getUrlParamValue('token_type'));
			storage('survival_time', (new Date().getTime() / 1000) + parseInt(getUrlParamValue('ttl')));
			// Remove the params in url
			var clean_uri = window.location.origin + window.location.pathname;
			window.history.replaceState({}, document.title, clean_uri);
		}

		var tokenType = storage('token_type');
		var survivalTime = storage('survival_time');
		var accessToken = storage('access-token');
		var userName = storage('userName');

		// 登录成功
		if (!((!tokenType || !accessToken) || (((+new Date) / 1000) | 0) > parseInt(survivalTime))) {
			// $('.head .sign').html('\
			// <a href="/user_admin/order_list" class="admin active">\
			// 	<span>Welcome, ' + userName + '</span>\
			// </a>');
			$('.head .sign').html('\
			<a href="/user_admin/order_list" class="admin-btn active">\
				<span>My Account</span>\
			</a>');
			$('.head_wap .waplga').html('<a class="fl admin active" href="/user_admin/order_list">Welcome, ' + userName + '</a>');
		}

		var code = getUrlParamValue('referral_code');

		if (code) {
			var nowTime = Math.ceil(Date.now() / 100);
			window.localStorage.setItem("referral_code", code, (nowTime + (4 * 60 * 60)));
		}

		function trackGlobalNavEvent(eventName, params) {
			var eventParams = Object.assign({
				page_name: getGlobalNavPageName(),
				page_path: window.location.pathname + window.location.search,
			}, params || {});

			if (typeof window.gtag === "function") {
				window.gtag("event", eventName, eventParams);
				return;
			}

			window.dataLayer = window.dataLayer || [];
			window.dataLayer.push(Object.assign({ event: eventName }, eventParams));
		}

		function getGlobalNavPageName() {
			var pathParts = window.location.pathname.split("/").filter(Boolean);
			if (!pathParts.length) return "home";

			return pathParts[pathParts.length - 1].replace(/\.html?$/i, "") || "home";
		}

		function getGlobalNavLinkUrl(link) {
			return link.getAttribute("href") || "";
		}

		function isGlobalHeaderLink(link) {
			return Boolean(link.closest(".head_box") || link.closest(".head_wap"));
		}

		function getGlobalNavItem(link) {
			var href = getGlobalNavLinkUrl(link).toLowerCase();
			var text = (link.textContent || "").trim().toLowerCase();

			if (href.indexOf("github.com") !== -1) return "github";
			if (href.indexOf("/new/windows.html") !== -1 || text === "windows") return "windows";
			if (href.indexOf("/new/feature/aacloud.html") !== -1 || href.indexOf("/new/aacloud.html") !== -1 || text.indexOf("aacloud") !== -1) return "aaCloud";
			if (href.indexOf("/new/feature") !== -1 || text.indexOf("feature") !== -1) return "features";
			if (href.indexOf("/new/pricing.html") !== -1 || text.indexOf("pricing") !== -1) return "pricing";
			if (href.indexOf("/new/ssl.html") !== -1 || text === "ssl") return "ssl";
			if (href.indexOf("/new/pro.html") !== -1 || text.indexOf("aapanel pro") !== -1) return "aapanel_pro";
			if (href.indexOf("aapanel.com/blog") !== -1 || text.indexOf("blog") !== -1) return "blog";
			if (href.indexOf("aapanel.com/forum") !== -1 || text.indexOf("forum") !== -1) return "forum";
			if (href.indexOf("/user_admin/login") !== -1 || text.indexOf("login") !== -1 || text.indexOf("sign in") !== -1) return "login";
			if (href.indexOf("/user_admin/register") !== -1 || text.indexOf("sign-up") !== -1 || text.indexOf("sign up") !== -1) return "signup";
			if (href.indexOf("/new/download") !== -1 || text.indexOf("install") !== -1 || text.indexOf("download") !== -1) return "download";

			return "";
		}

		function initGlobalNavClickTracking() {
			document.addEventListener("click", function (event) {
				var target = event.target;
				if (!target || !target.closest) return;

				var navLink = target.closest("a");
				if (!navLink || !isGlobalHeaderLink(navLink)) return;

				var navItem = getGlobalNavItem(navLink);
				if (!navItem) return;

				trackGlobalNavEvent("nav_click", {
					nav_item: navItem,
					link_url: getGlobalNavLinkUrl(navLink),
				});
			}, true);
		}

		initGlobalNavClickTracking();

		$(function () {
			function initFeatureMenuIntent() {
				var closeTimer = null;
				var closeDelay = 320;
				var featureMenu = document.querySelector('.navigation.nav > span.nav-features');
				if (!featureMenu) return;

				function openFeatureMenu() {
					clearTimeout(closeTimer);
					featureMenu.classList.add('sub-menu-open');
				}

				function closeFeatureMenu() {
					clearTimeout(closeTimer);
					closeTimer = setTimeout(function () {
						featureMenu.classList.remove('sub-menu-open');
					}, closeDelay);
				}

				featureMenu.addEventListener('mouseenter', openFeatureMenu);
				featureMenu.addEventListener('mouseleave', closeFeatureMenu);
				featureMenu.addEventListener('focusin', openFeatureMenu);
				featureMenu.addEventListener('focusout', closeFeatureMenu);
			}

			initFeatureMenuIntent();

			$('.whead i,.wapnavtop i').click(function () {
				$('.wapnav').toggleClass('wapnav_active');
				$('.wpnvbg').toggleClass('wpnvbg_active');
			});

			$('.wpnvbg').click(function () {
				$('.wapnav').removeClass('wapnav_active');
				$('.wpnvbg').removeClass('wpnvbg_active');
			});

			$('.wpheadhide a').click(function () {
				$('.wpnvbg').click();
			});

			$('.wapprda').click(function () {
				$(this).siblings('.wpheadhide').slideToggle();
				$(this).toggleClass('wapprda_active');
			});

			// 设置路由地址
			function setNavAactive() {
				var path = location.pathname.replace(/\/+$/, '') || '/';
				var navLink = $('.navigation a, .head_box .sign a, .head_box .install-btn, .wapnava a, .waplga a');

				$('.navigation span, .head_wap span, .wpheadhide').removeClass('active wapprda_active');
				navLink.removeClass('active wapprda_active');

				function getLinkPath(url) {
					if (!url || url.indexOf('javascript:') === 0) return '';
					var link = $('<a></a>').attr('href', url)[0];
					return link.pathname ? link.pathname.replace(/\/+$/, '') || '/' : '';
				}

				function getActiveKey(url) {
					var hrefPath = getLinkPath(url);

					if (!hrefPath) return '';
					if (hrefPath === '/') return 'home';
					if (hrefPath.indexOf('/new/feature') === 0) return 'features';
					if (hrefPath === '/new/pricing.html') return 'pricing';
					if (hrefPath === '/new/ssl.html') return 'ssl';
					if (hrefPath === '/new/pro.html') return 'pro';
					if (hrefPath === '/new/download.html') return 'download';
					if (hrefPath === '/user_admin/login') return 'login';
					if (hrefPath === '/user_admin/register') return 'signup';

					return '';
				}

				function getExternalActiveKey(url) {
					if (!url) return '';
					if (url.indexOf('aapanel.com/blog') > -1) return 'blog';
					if (url.indexOf('aapanel.com/forum') > -1) return 'forum';
					return '';
				}

				function isActiveNavLink(link) {
					var href = link.attr('href') || '';
					var hrefPath = getLinkPath(href);
					var linkKey = getActiveKey(href);
					var text = (link.text() || '').trim().toLowerCase();

					if (activeKey === 'features') {
						if (link.closest('.sub-menu-item').length || link.parent().hasClass('wpheadhide')) {
							return hrefPath === path;
						}

						return linkKey === 'features' || text.indexOf('features') > -1;
					}

					return linkKey === activeKey || getExternalActiveKey(href) === activeKey;
				}

				var activeKey = getActiveKey(path);
				if (!activeKey) return;

				var activeNav = navLink.filter(function () {
					return isActiveNavLink($(this));
				});

				activeNav.each(function () {
					var link = $(this);
					var box = link.parent();

					if (box.hasClass('sub-menu-item')) {
						box.parents('span').addClass('active');
						link.addClass('active');
						return;
					}

					if (box.hasClass('wpheadhide')) {
						box.addClass('active wapprda_active').show();
						box.prev('.wapprda').addClass('active wapprda_active').parent().addClass('active');
						link.addClass('active');
						return;
					}

					box.addClass('active');
					link.addClass('active');
				});
			}

			setNavAactive();
		});
		$(document).ready(function () {
			// 添加点击事件
			$('.black-box').click(function () {
				window.location.href = '/act/aapanel_9th.html';
			});
		});

		// 获取活动信息--下面是黑五活动下架时删除
		$(document).ready(function () {
			var activity_id = 15; // 活动id
			var showModal = false; // 是否需要显示弹窗
			var server_time = null; // 当前服务器时间
			var end_timer = null; // 倒计时时间

			// 获取活动信息
			get_activity_info();

			function get_activity_info() {
				$.ajax({
					url: '/api/activity/' + activity_id,
					type: 'GET',
					contentType: 'application/json',
					success: function (datas) {
						server_time = datas.nonce;
						if (!datas.res.is_finished) {
							$('.black-box').css({
								'display': 'flex',
							});
							$('.head_pc').css('margin-bottom', '50px');
							if (datas.nonce < datas.res.start_time) {
								$('.active-text').text('Starting In');
								localStorage.setItem('isFinish', true);
								startCountdown(datas.nonce, datas.res.start_time);
							} else {
								$('.active-text').text('Ending In');
								if (showModal) {
									localStorage.setItem('isFinish', false);
								}
								startCountdown(datas.nonce, datas.res.end_time);
							}
						} else {
							localStorage.setItem('isFinish', true);
						}
					},
					error: function (xhr) {
						console.error('Request failed with status:', xhr.status);
					}
				});
			}

			function startCountdown(serverTime, endTime) {
				var dateBox = $('#date_box1');

				// 将时间戳转换为 Date 对象
				var serverDate = new Date(serverTime * 1000); // 将服务器时间转换为毫秒
				var endDate = new Date(endTime * 1000); // 将结束时间转换为毫秒

				function updateCountdown() {
					var now = new Date(); // 当前时间
					var timeStamp = endDate - now; // 计算剩余的毫秒数

					if (timeStamp > 0) {
						var days = Math.floor(timeStamp / (1000 * 60 * 60 * 24));
						var hours = Math.floor((timeStamp % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
						var minutes = Math.floor((timeStamp % (1000 * 60 * 60)) / (1000 * 60));
						var seconds = Math.floor((timeStamp % (1000 * 60)) / 1000);

						// 格式化时间
						var _days = String(days).padStart(2, '0');
						var _hours = String(hours).padStart(2, '0');
						var _minutes = String(minutes).padStart(2, '0');
						var _seconds = String(seconds).padStart(2, '0');

						// 更新页面内容
						dateBox.html(`
		                        <div class="date_item"><span class="time">${_days}</span><span class="time-text">Days</span></div>
		                        <div class="date_item"><span class="time">${_hours}</span><span class="time-text">Hour</span></div>
		                        <div class="date_item"><span class="time">${_minutes}</span><span class="time-text">Minutes</span></div>
		                        <div class="date_item"><span class="time">${_seconds}</span><span class="time-text">Sec</span></div>
		                    `);
					} else {
						clearInterval(countdownInterval);
					}
				}

				// 每秒更新一次
				var countdownInterval = setInterval(updateCountdown, 1000);
				updateCountdown(); // 初始调用一次以显示倒计时
			}

		})
	</script>
