	<script>
    const HOME_TRACKING_DEBUG = false;
    const invite_code = location.search.match(/\?invite_code=([0-9A-z]*)/);
    if (invite_code) {
        sessionStorage.setItem('invite_code', invite_code[1]);
    }

    document.addEventListener('DOMContentLoaded', function() {
        function trackHomeEvent(eventName, params) {
            const eventParams = Object.assign({
                page_name: 'home',
                debug_mode: HOME_TRACKING_DEBUG,
            }, params || {});

            if (HOME_TRACKING_DEBUG && window.console && typeof window.console.info === 'function') {
                window.console.info('[home tracking]', eventName, eventParams);
            }

            if (typeof window.gtag === 'function') {
                window.gtag('event', eventName, eventParams);
                return;
            }

            window.dataLayer = window.dataLayer || [];
            window.dataLayer.push(Object.assign({ event: eventName }, eventParams));
        }

        function getHomeLinkUrl(link) {
            return link.getAttribute('href') || '';
        }

        function getHomeModuleMeta(moduleName) {
            const moduleMap = {
                who_we_are: { module_title: 'who_we_are', module_order: 1 },
                why_choose_aapanel: { module_title: 'Why Choose aaPanel', module_order: 2 },
                features: { module_title: 'Core Features', module_order: 3 },
                aapanel_use_cases: { module_title: 'Powering Every Use Case', module_order: 4 },
                comparison: { module_title: 'aaPanel vs Other Control Panels', module_order: 5 },
                testimonials: { module_title: 'What Our Users Say', module_order: 6 },
                safe_efficient_server_panel: { module_title: 'Ready to Get Started', module_order: 7 },
                faq: { module_title: 'Frequently Asked Questions', module_order: 8 },
                ai_assistant_float: { module_title: 'aaPanel AI Assistant', module_order: 9 },
                bottom: { module_title: 'bottom', module_order: 10 },
            };

            return moduleMap[moduleName] || {
                module_title: moduleName,
                module_order: 0,
            };
        }

        function getHomeModuleEventParams(moduleName) {
            const moduleMeta = getHomeModuleMeta(moduleName);

            return {
                module_name: moduleName,
                module_title: moduleMeta.module_title,
                module_order: moduleMeta.module_order,
            };
        }

        function getCurrentHomeModuleParams() {
            const moduleElements = Array.from(document.querySelectorAll('[data-home-module]'));
            if (!moduleElements.length) return {};

            const viewportMiddle = window.innerHeight / 2;
            let currentModuleElement = moduleElements[0];

            moduleElements.forEach(function(element) {
                const rect = element.getBoundingClientRect();
                if (rect.top <= viewportMiddle && rect.bottom >= 0) {
                    currentModuleElement = element;
                }
            });

            const moduleParams = getHomeModuleEventParams(currentModuleElement.getAttribute('data-home-module') || '');

            return {
                current_module_name: moduleParams.module_name,
                current_module_title: moduleParams.module_title,
                current_module_order: moduleParams.module_order,
            };
        }

        function initHomeScrollTracking() {
            const thresholds = [25, 50, 75, 90, 100];
            const triggeredDepths = {};
            let isScrollDepthTicking = false;

            function getScrollDepth() {
                const doc = document.documentElement;
                const body = document.body;
                const scrollTop = window.pageYOffset || doc.scrollTop || body.scrollTop || 0;
                const scrollHeight = Math.max(body.scrollHeight, doc.scrollHeight, body.offsetHeight, doc.offsetHeight, body.clientHeight, doc.clientHeight);
                const maxScroll = Math.max(scrollHeight - window.innerHeight, 1);

                return Math.min(100, Math.round((scrollTop / maxScroll) * 100));
            }

            function checkScrollDepth() {
                isScrollDepthTicking = false;
                const currentDepth = getScrollDepth();

                thresholds.forEach(function(threshold) {
                    if (currentDepth >= threshold && !triggeredDepths[threshold]) {
                        triggeredDepths[threshold] = true;
                        trackHomeEvent('home_scroll_depth', Object.assign({
                            scroll_depth: threshold,
                        }, getCurrentHomeModuleParams()));
                    }
                });
            }

            function scheduleScrollDepthCheck() {
                if (isScrollDepthTicking) return;
                isScrollDepthTicking = true;
                window.requestAnimationFrame(checkScrollDepth);
            }

            window.addEventListener('scroll', scheduleScrollDepthCheck, { passive: true });
            window.addEventListener('resize', scheduleScrollDepthCheck);
            window.addEventListener('load', scheduleScrollDepthCheck);
            scheduleScrollDepthCheck();
        }

        function initHomeModuleViewTracking() {
            const footer = document.querySelector('.foot');
            if (footer && !footer.hasAttribute('data-home-module')) {
                footer.setAttribute('data-home-module', 'bottom');
            }

            const moduleElements = Array.from(document.querySelectorAll('[data-home-module]'));
            const viewedModules = {};

            function trackModuleView(element) {
                const moduleName = element.getAttribute('data-home-module');
                if (!moduleName || viewedModules[moduleName]) return;

                viewedModules[moduleName] = true;
                trackHomeEvent('home_module_view', getHomeModuleEventParams(moduleName));
            }

            if ('IntersectionObserver' in window) {
                const moduleObserver = new IntersectionObserver(function(entries, observer) {
                    entries.forEach(function(entry) {
                        if (entry.isIntersecting) {
                            trackModuleView(entry.target);
                            observer.unobserve(entry.target);
                        }
                    });
                }, {
                    threshold: 0.2,
                });

                moduleElements.forEach(function(element) {
                    moduleObserver.observe(element);
                });
                return;
            }

            moduleElements.forEach(trackModuleView);
        }

        function initHomeClickTracking() {
            document.addEventListener('click', function(event) {
                const target = event.target;
                if (!target || !target.closest) return;

                const ctaLink = target.closest('[data-home-track-click]');
                if (!ctaLink) return;

                const moduleName = ctaLink.getAttribute('data-module-name') || '';
                trackHomeEvent('home_module_click', Object.assign(getHomeModuleEventParams(moduleName), {
                    button_name: ctaLink.getAttribute('data-button-name') || '',
                    link_url: getHomeLinkUrl(ctaLink),
                }));
            });
        }

        initHomeScrollTracking();
        initHomeModuleViewTracking();
        initHomeClickTracking();

        const aiFloatBox = document.getElementById('aiFloatBox');
        if (aiFloatBox && !sessionStorage.getItem('ai_board_closed')) {
            aiFloatBox.classList.remove('is-closing');
            aiFloatBox.style.display = 'block';
        }

        let isDragging = false;
        let animationId = null;
        const container = document.getElementById('sliderContainer');
        const afterImg = document.getElementById('afterImg');
        const slider = document.getElementById('slider');

        document.querySelectorAll('.home-new .faq-q').forEach(function(question) {
            question.addEventListener('click', function() {
                const item = question.closest('.faq-item');
                if (item) item.classList.toggle('active');
            });
        });

        if (!container || !afterImg || !slider) return;

        slider.addEventListener('mousedown', function(e) {
            isDragging = true;
            slider.style.transform = 'scale(1.1)';
            e.preventDefault();
        });

        document.addEventListener('mouseup', function() {
            isDragging = false;
            slider.style.transform = 'scale(1)';
            if (animationId) {
                cancelAnimationFrame(animationId);
                animationId = null;
            }
        });

        document.addEventListener('mousemove', function(e) {
            if (!isDragging) return;
            if (animationId) cancelAnimationFrame(animationId);
            animationId = requestAnimationFrame(function() {
                const rect = container.getBoundingClientRect();
                const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
                const percent = (x / rect.width) * 100;
                afterImg.style.clipPath = 'inset(0 ' + (100 - percent) + '% 0 0)';
                slider.style.left = percent + '%';
            });
        });

        slider.addEventListener('touchstart', function(e) {
            isDragging = true;
            slider.style.transform = 'scale(1.1)';
            e.preventDefault();
        });

        document.addEventListener('touchend', function() {
            isDragging = false;
            slider.style.transform = 'scale(1)';
        });

        document.addEventListener('touchmove', function(e) {
            if (!isDragging) return;
            e.preventDefault();
            const touch = e.touches[0];
            const rect = container.getBoundingClientRect();
            const x = Math.max(0, Math.min(touch.clientX - rect.left, rect.width));
            const percent = (x / rect.width) * 100;
            afterImg.style.clipPath = 'inset(0 ' + (100 - percent) + '% 0 0)';
            slider.style.left = percent + '%';
        });
    });

    function closeAiFloat() {
        const box = document.getElementById('aiFloatBox');
        if (!box || box.classList.contains('is-closing')) return;

        box.classList.add('is-closing');
        setTimeout(function() {
            box.style.display = 'none';
            box.classList.remove('is-closing');
            sessionStorage.setItem('ai_board_closed', 'true');
        }, 280);
    }

    setTimeout(function() {
        const viewEvent = localStorage.getItem('isFinish');
        const isOpen = getCookie('isClose');

        if (viewEvent !== 'false' || isOpen === 'true' || !window.layer || typeof window.layer.open !== 'function') return;

        window.layer.open({
            type: 1,
            area: ['600px', '440px'],
            title: false,
            shade: 0.5,
            closeBtn: 2,
            content: '\
                <div class="black_layer">\
                    <div class="title_h1">Black Friday</div>\
                    <div class="title_h1">And Cyber Monday</div>\
                    <div class="divider"></div>\
                    <div class="title_h3">\
                        <svg width="300" height="100" class="svg">\
                            <text x="50%" y="50%" text-anchor="middle" dominant-baseline="middle" font-size="60" class="text">Big Sale!</text>\
                        </svg>\
                        <div class="title_h2">aaPanel-Pro for only $399/Lifetime</div>\
                    </div>\
                    <div class="title_h4"><span class="curror">^</span></div>\
                    <button type="button" class="button">Get deal</button>\
                </div>',
            end: function() {
                setCookies({ isClose: true }, 1);
            },
            success: function(layerElement, layerIndex) {
                const dealButton = document.querySelector('.black_layer .button');
                if (!dealButton) return;

                dealButton.addEventListener('click', function() {
                    setCookies({ isClose: true }, 1);
                    window.layer.close(layerIndex);
                    window.location.href = '/black_friday';
                });
            },
        });
    }, 2000);

    function getCookie(name) {
        const value = '; ' + document.cookie;
        const parts = value.split('; ' + name + '=');
        if (parts.length === 2) return parts.pop().split(';').shift();
        return null;
    }

    function setCookies(obj, limitTime) {
        const expires = new Date(new Date().getTime() + limitTime * 24 * 60 * 60 * 1000).toUTCString();
        Object.keys(obj).forEach(function(key) {
            document.cookie = key + '=' + obj[key] + ';expires=' + expires;
        });
    }
</script>

</body>

</html>
